#!/usr/bin/env node
// SPDX-License-Identifier: MIT
// Generated by metaharness — the `crechebooks-harness` CLI entry point.
//
// This is plain ESM JavaScript on purpose: it runs as-is via `npx crechebooks-harness`
// with NO build step. `npm run build` (tsc) is only needed if you extend the
// TypeScript in src/. The published package ships this file directly (see the
// "bin" + "files" fields in package.json), so `npx crechebooks-harness` works the moment
// `npm install` has resolved @metaharness/kernel + @metaharness/host-claude-code.

import path from 'node:path';
import { loadKernel } from '@metaharness/kernel';
import adapter from '@metaharness/host-claude-code';

const HARNESS_NAME = 'crechebooks-harness';

/** `crechebooks-harness init` — boot the kernel + host adapter and report status. */
async function init() {
  const kernel = await loadKernel();
  const info = kernel.kernelInfo();
  console.log(`${HARNESS_NAME} — kernel ${info.version} (${kernel.backend})`);
  console.log(`Host adapter: ${adapter.name}`);
  console.log(`Run \`${HARNESS_NAME} doctor\` to verify the install.`);
  return 0;
}

/** `crechebooks-harness doctor` — verify the install end-to-end (kernel + host resolve). */
async function doctor() {
  const kernel = await loadKernel();
  const info = kernel.kernelInfo();
  const checks = [
    ['kernel loads', !!kernel],
    ['kernel reports a version', typeof info.version === 'string' && info.version.length > 0],
    ['kernel backend is native|wasm|js', ['native', 'wasm', 'js'].includes(kernel.backend)],
    ['host adapter has a name', typeof adapter?.name === 'string' && adapter.name.length > 0],
  ];
  let ok = true;
  for (const [label, pass] of checks) {
    console.log(`${pass ? 'PASS' : 'FAIL'} ${label}`);
    if (!pass) ok = false;
  }
  console.log(
    ok
      ? `\n${HARNESS_NAME}: all checks passed (kernel ${info.version}, ${kernel.backend} backend, host ${adapter.name})`
      : `\n${HARNESS_NAME}: doctor found problems`,
  );
  return ok ? 0 : 1;
}

/**
 * `crechebooks-harness mcp <start|index>` — run a stdio MCP server. `start`
 * serves the harness toolset (plan/review/test/kernel); `index` serves the
 * read-only code-search toolset. Both are wired in .claude/settings.json.
 */
async function mcp(args) {
  const sub = args[0] ?? 'start';
  const { createRegistry, serve } = await import('../src/mcp/server.js');
  if (sub === 'start') {
    const { harnessToolset } = await import('../src/mcp/tools.js');
    await serve(createRegistry(HARNESS_NAME, harnessToolset), { name: HARNESS_NAME, version: '0.1.0' });
    return 0;
  }
  if (sub === 'index') {
    const { indexToolset } = await import('../src/mcp/index-tools.js');
    await serve(createRegistry('code_index', indexToolset), { name: 'code_index', version: '0.1.0' });
    return 0;
  }
  if (sub === 'domain') {
    const { domainToolset } = await import('../src/mcp/domain-tools.js');
    const { mutationToolset } = await import('../src/mcp/mutation-tools.js');
    await serve(createRegistry('crechebooks', [...domainToolset, ...mutationToolset]), { name: 'crechebooks', version: '0.1.0' });
    return 0;
  }
  console.error(`Unknown mcp subcommand: ${sub}. Try \`mcp start\`, \`mcp index\`, or \`mcp domain\`.`);
  return 2;
}

// ── Release gates ───────────────────────────────────────────────────────────
// Zero-dependency provenance + audit gates (Node's built-in crypto for Ed25519).

/** The harness package root (bin/ → ..). */
function harnessRoot() {
  return path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..');
}

/** `manifest` — refresh the integrity manifest to current source. */
async function manifestCmd() {
  const { refreshManifest } = await import('../src/gates/manifest.js');
  const { changed, count } = refreshManifest(harnessRoot(), { now: new Date().toISOString() });
  console.log(changed ? `manifest updated — ${count} files hashed` : `manifest already current — ${count} files`);
  return 0;
}

/** `sbom` — emit an SPDX-2.3 SBOM to .harness/sbom.spdx.json. */
async function sbomCmd() {
  const { buildSbom } = await import('../src/gates/sbom.js');
  const { writeFileSync } = await import('node:fs');
  const root = harnessRoot();
  const doc = buildSbom(root, { now: new Date().toISOString() });
  const out = path.join(root, '.harness', 'sbom.spdx.json');
  writeFileSync(out, JSON.stringify(doc, null, 2) + '\n');
  console.log(`SBOM written: ${path.relative(root, out)} — ${doc.packages.length} packages (SPDX-2.3)`);
  return 0;
}

/** `sign` — refresh the manifest, then Ed25519-sign it into a witness. */
async function signCmd() {
  const { refreshManifest } = await import('../src/gates/manifest.js');
  const { signManifest } = await import('../src/gates/sign.js');
  const root = harnessRoot();
  refreshManifest(root, { now: new Date().toISOString() });
  const { witness, keypairCreated } = signManifest(root, { now: new Date().toISOString() });
  if (keypairCreated) console.log('generated a new Ed25519 keypair in .harness/keys/ (signing.key is gitignored)');
  console.log(`signed manifest ${witness.manifest_sha256.slice(0, 16)}… → .harness/witness.json`);
  return 0;
}

/** `verify` — check the witness signature AND manifest integrity. */
async function verifyCmd() {
  const { verifyWitness } = await import('../src/gates/sign.js');
  const { checkIntegrity } = await import('../src/gates/manifest.js');
  const root = harnessRoot();
  const integ = checkIntegrity(root);
  const v = verifyWitness(root);
  console.log(`${integ.ok ? 'PASS' : 'FAIL'} manifest integrity — ${integ.ok ? `${integ.count} files` : `missing ${integ.missing.length}, changed ${integ.changed.length}, extra ${integ.extra.length}`}`);
  console.log(`${v.ok ? 'PASS' : 'FAIL'} witness signature — ${v.reason}`);
  return integ.ok && v.ok ? 0 : 1;
}

/** `mcp-scan` — static security audit of the MCP surface. */
async function mcpScanCmd() {
  const { scanMcp } = await import('../src/gates/mcp-scan.js');
  const { findings, ok, worst } = scanMcp(harnessRoot());
  for (const f of findings) console.log(`${f.severity.toUpperCase().padEnd(6)} ${f.rule} — ${f.detail}`);
  console.log(`${findings.length ? '\n' : ''}mcp-scan: ${findings.length} finding(s), worst: ${worst} → ${ok ? 'PASS' : 'FAIL'}`);
  return ok ? 0 : 1;
}

/** `validate` — run every release gate and aggregate PASS/FAIL. */
async function validateCmd() {
  const { validate } = await import('../src/gates/validate.js');
  const { ok, gates } = await validate(harnessRoot());
  for (const g of gates) {
    const status = g.skipped ? 'SKIP' : g.ok ? 'PASS' : 'FAIL';
    console.log(`${status.padEnd(5)} ${g.name.padEnd(20)} ${g.detail}`);
  }
  console.log(`\n${HARNESS_NAME}: ${ok ? 'all gates passed' : 'gate failures above'}`);
  return ok ? 0 : 1;
}

/**
 * Dispatch one CLI invocation. Exported (not just run on import) so a test can
 * drive it without spawning a subprocess. Returns the intended exit code.
 */
export async function run(argv) {
  const cmd = argv[0] ?? 'init';
  switch (cmd) {
    case 'init':
      return init();
    case 'doctor':
      return doctor();
    case 'mcp':
      return mcp(argv.slice(1));
    case 'manifest':
      return manifestCmd();
    case 'sbom':
      return sbomCmd();
    case 'sign':
      return signCmd();
    case 'verify':
      return verifyCmd();
    case 'mcp-scan':
      return mcpScanCmd();
    case 'validate':
      return validateCmd();
    case '--version':
    case '-v': {
      const kernel = await loadKernel();
      console.log(kernel.version());
      return 0;
    }
    case '--help':
    case '-h':
      console.log(
        `Usage: ${HARNESS_NAME} <command>\n\n` +
          `  init          boot the kernel + host adapter (default)\n` +
          `  doctor        verify the install end-to-end\n` +
          `  mcp start     run the harness MCP server (stdio)\n` +
          `  mcp index     run the read-only code-index MCP server (stdio)\n` +
          `  mcp domain    run the read-only CrecheBooks domain MCP server (stdio)\n` +
          `\n  Release gates:\n` +
          `  manifest      refresh the integrity manifest to current source\n` +
          `  sbom          emit an SPDX-2.3 software bill of materials\n` +
          `  sign          Ed25519-sign the manifest (witness provenance)\n` +
          `  verify        verify the witness signature + manifest integrity\n` +
          `  mcp-scan      static security audit of the MCP tool surface\n` +
          `  validate      run every release gate (PASS/FAIL report)\n` +
          `\n  --version     print the kernel version`,
      );
      return 0;
    default:
      console.error(`Unknown command: ${cmd}. Try \`${HARNESS_NAME} --help\`.`);
      return 2;
  }
}

// CLI guard: execute only when invoked directly (not when imported by a test).
// npm's bin shims pass a NON-normalized argv[1] (e.g. ".../.bin/../<pkg>/bin/cli.js"
// on Windows) and may differ in case, so realpath BOTH sides before comparing —
// a naive string === misses the npx/shim path and the CLI silently no-ops.
import { fileURLToPath } from 'node:url';
import { realpathSync } from 'node:fs';
import { argv } from 'node:process';
const invokedDirectly = (() => {
  if (!argv[1]) return false;
  try {
    const a = realpathSync(argv[1]);
    const b = realpathSync(fileURLToPath(import.meta.url));
    return process.platform === 'win32' ? a.toLowerCase() === b.toLowerCase() : a === b;
  } catch {
    return false;
  }
})();
if (invokedDirectly) {
  run(argv.slice(2))
    .then((code) => process.exit(code))
    .catch((err) => {
      console.error(err);
      process.exit(1);
    });
}
